INSERT INTO `site_settings` (`id`,`key`,`locale`,`value`) VALUES (UUID(), 'homepage_hero', 'en', '{"season": "spring", "title": "The Bounty of the Seed", "highlight": "Begins", "suffix": "with the Soil", "description": "Vista Seeds delivers sustainable success in agriculture with high-yield, reliable seed varieties.", "badge": "2026 Spring Season", "image_url": "/assets/hero/spring-field.jpg", "cta_label": "Explore Products", "cta_href": "/urunler", "secondary_label": "Planting Guide", "secondary_href": "/sss"}') ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
INSERT INTO `site_settings` (`id`,`key`,`locale`,`value`) VALUES (UUID(), 'homepage_hero', 'de', '{"season": "spring", "title": "Der Reichtum des Saatguts", "highlight": "beginnt", "suffix": "mit dem Boden", "description": "Vista Seeds bietet mit ertragreichen und zuverlässigen Saatgutsorten nachhaltigen Erfolg in der Landwirtschaft.", "badge": "Frühjahrssaison 2026", "image_url": "/assets/hero/spring-field.jpg", "cta_label": "Produkte entdecken", "cta_href": "/urunler", "secondary_label": "Anbauleitfaden", "secondary_href": "/sss"}') ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
INSERT INTO `site_settings` (`id`,`key`,`locale`,`value`) VALUES (UUID(), 'homepage_sections', 'en', '{"stats": [{"value": "137K+", "label": "Customers"}, {"value": "8+", "label": "Varieties"}, {"value": "35+", "label": "Years of Experience"}, {"value": "%95", "label": "Germination Rate"}], "values": [{"icon": "sun", "title": "High Yield", "description": "Vista Seeds offers high-yield seeds developed with modern production techniques."}, {"icon": "shield", "title": "Quality and Trust", "description": "All our seeds go through quality control processes. We produce healthy, resilient seeds that farmers can sow with confidence."}, {"icon": "users", "title": "Regional Adaptation", "description": "Thanks to varieties suited to different climate and soil conditions, we enable successful production in every region."}, {"icon": "beaker", "title": "R&D and Innovation", "description": "Continuous development of new varieties at our own research facilities, hybrid breeding programs and improvement studies."}], "timeline": [{"year": "1988", "title": "Foundation", "description": "Operations began as Aksu Gübre (fertilizer)."}, {"year": "1992", "title": "Start of Production", "description": "While Aksu Gübre''s commercial activities continued, our founder Mr. Mümin Şahin oversaw the first production activities in a covered growing area."}, {"year": "2006", "title": "Bereket Fide", "description": "Expansion into new markets with the founding of Bereket Fide."}, {"year": "2015", "title": "Bereket İnşaat - Tolkan Architecture", "description": "Entry into the construction sector through the Bereket İnşaat subsidiary, led by Tolkan Architecture."}, {"year": "2020", "title": "Energy", "description": "Establishment of the first energy facility in line with a sustainable agriculture approach."}, {"year": "2025", "title": "Atakan Tohum / Vista Seeds", "description": "Founding of our technology-integrated, modern producer and supplier seed company."}], "seasonal_picks_title": "This Season''s Picks", "seasonal_picks_description": "Explore our most suitable varieties for spring planting."}') ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
INSERT INTO `site_settings` (`id`,`key`,`locale`,`value`) VALUES (UUID(), 'homepage_sections', 'de', '{"stats": [{"value": "137K+", "label": "Kunden"}, {"value": "8+", "label": "Sorten"}, {"value": "35+", "label": "Jahre Erfahrung"}, {"value": "%95", "label": "Keimrate"}], "values": [{"icon": "sun", "title": "Hoher Ertrag", "description": "Vista Seeds bietet ertragreiches Saatgut, das mit modernen Produktionstechniken entwickelt wurde."}, {"icon": "shield", "title": "Qualität und Vertrauen", "description": "Alle unsere Saatgüter durchlaufen Qualitätskontrollprozesse. Wir produzieren gesundes, widerstandsfähiges Saatgut, das Landwirte mit Vertrauen aussäen können."}, {"icon": "users", "title": "Regionale Anpassung", "description": "Dank Sorten, die an unterschiedliche Klima- und Bodenbedingungen angepasst sind, ermöglichen wir eine erfolgreiche Produktion in jeder Region."}, {"icon": "beaker", "title": "F&E und Innovation", "description": "Kontinuierliche Entwicklung neuer Sorten in unseren eigenen Forschungseinrichtungen, Hybridzuchtprogramme und Verbesserungsstudien."}], "timeline": [{"year": "1988", "title": "Gründung", "description": "Die Tätigkeit begann als Aksu Gübre (Dünger)."}, {"year": "1992", "title": "Produktionsbeginn", "description": "Während die Handelstätigkeit von Aksu Gübre fortgesetzt wurde, beaufsichtigte unser Gründer Herr Mümin Şahin die ersten Produktionstätigkeiten in einer geschützten Anbaufläche."}, {"year": "2006", "title": "Bereket Fide", "description": "Expansion in neue Märkte mit der Gründung von Bereket Fide."}, {"year": "2015", "title": "Bereket İnşaat - Tolkan Architektur", "description": "Einstieg in die Baubranche über die Tochtergesellschaft Bereket İnşaat unter der Leitung von Tolkan Architektur."}, {"year": "2020", "title": "Energie", "description": "Errichtung der ersten Energieanlage im Einklang mit einem nachhaltigen Landwirtschaftsansatz."}, {"year": "2025", "title": "Atakan Tohum / Vista Seeds", "description": "Gründung unseres technologieintegrierten, modernen Saatgutunternehmens als Produzent und Lieferant."}], "seasonal_picks_title": "Unsere Empfehlungen für diese Saison", "seasonal_picks_description": "Entdecken Sie unsere am besten geeigneten Sorten für die Frühjahrsaussaat."}') ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
