INSERT INTO `site_settings` (`id`,`key`,`locale`,`value`) VALUES (UUID(), 'homepage_feature_panels', 'en', '{"title": "From Production to Brand", "subtitle": "Selected images reflecting Vista Seeds'' seed quality, sustainable agriculture approach and corporate values.", "items": [{"title": "The Bounty of the Seed", "description": "The core message emphasizing that success in agriculture begins with the right seed.", "image_url": "/uploads/homepage/vistaseeds/features/tohumun-bereketi-01KKF1351HG1HJ9VJ2NCNC1EA7.webp", "image_alt": "Vista Seeds bounty of the seed image"}, {"title": "High-Yield Seeds", "description": "A visual block highlighting the focus on high yield and reliable varieties.", "image_url": "/uploads/homepage/vistaseeds/features/yuksek-verimli-tohumlar-01KKBNPQNZ111C9XNQ5SZR917C.webp", "image_alt": "High-yield seeds image"}, {"title": "Sustainable Agriculture Approach", "description": "Emphasis on environmentally conscious production and a sustainable future.", "image_url": "/uploads/homepage/vistaseeds/features/surdurulebilir-tarim-01KKBP4H1ZRJG4NC56YH86XW1K.webp", "image_alt": "Sustainable agriculture approach image"}, {"title": "Quality and Trust", "description": "A narrative of quality standards and a reliable corporate structure.", "image_url": "/uploads/homepage/vistaseeds/features/kalite-ve-guven-01KKBP4HBBKX99XTFY3PV0YNVD.webp", "image_alt": "Quality and trust image"}], "cover_image_url": "/uploads/homepage/vistaseeds/why-choose/neden-bizi-secmelisiniz-01KK93KQEVWW8KD5JD84V8ZZMZ.webp", "cover_image_alt": "Why choose us image"}') ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
INSERT INTO `site_settings` (`id`,`key`,`locale`,`value`) VALUES (UUID(), 'homepage_feature_panels', 'de', '{"title": "Von der Produktion zur Marke", "subtitle": "Ausgewählte Bilder, die die Saatgutqualität, den nachhaltigen Landwirtschaftsansatz und die Unternehmenswerte von Vista Seeds widerspiegeln.", "items": [{"title": "Der Reichtum des Saatguts", "description": "Die Kernbotschaft, dass Erfolg in der Landwirtschaft mit dem richtigen Saatgut beginnt.", "image_url": "/uploads/homepage/vistaseeds/features/tohumun-bereketi-01KKF1351HG1HJ9VJ2NCNC1EA7.webp", "image_alt": "Vista Seeds Bild zum Reichtum des Saatguts"}, {"title": "Ertragreiches Saatgut", "description": "Ein visueller Block, der den Fokus auf hohen Ertrag und zuverlässige Sorten hervorhebt.", "image_url": "/uploads/homepage/vistaseeds/features/yuksek-verimli-tohumlar-01KKBNPQNZ111C9XNQ5SZR917C.webp", "image_alt": "Bild von ertragreichem Saatgut"}, {"title": "Nachhaltiger Landwirtschaftsansatz", "description": "Betonung umweltbewusster Produktion und einer nachhaltigen Zukunft.", "image_url": "/uploads/homepage/vistaseeds/features/surdurulebilir-tarim-01KKBP4H1ZRJG4NC56YH86XW1K.webp", "image_alt": "Bild zum nachhaltigen Landwirtschaftsansatz"}, {"title": "Qualität und Vertrauen", "description": "Eine Erzählung über Qualitätsstandards und eine zuverlässige Unternehmensstruktur.", "image_url": "/uploads/homepage/vistaseeds/features/kalite-ve-guven-01KKBP4HBBKX99XTFY3PV0YNVD.webp", "image_alt": "Bild zu Qualität und Vertrauen"}], "cover_image_url": "/uploads/homepage/vistaseeds/why-choose/neden-bizi-secmelisiniz-01KK93KQEVWW8KD5JD84V8ZZMZ.webp", "cover_image_alt": "Bild „Warum Sie uns wählen sollten“"}') ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
