INSERT INTO `site_settings` (`id`,`key`,`locale`,`value`) VALUES (UUID(), 'planting_guide', 'en', '{"title": "Planting Guide", "description": "Seasonal planting recommendations and care tips.", "seasons": [{"key": "spring", "label": "Spring", "months": "March — May", "tips": ["Soil temperature should be at least 15°C", "Seedling preparation should begin at the end of February", "The first irrigation should be light and even"], "recommended_tags": ["bahar", "fide"]}, {"key": "summer", "label": "Summer", "months": "June — August", "tips": ["Shading should be applied against heat stress", "Efficiency should be increased with drip irrigation", "Attention should be paid to harvest timing"], "recommended_tags": ["yaz", "sicaga-dayanikli"]}, {"key": "autumn", "label": "Autumn", "months": "September — November", "tips": ["Ideal planting period for winter vegetables", "Soil preparation and fertilization are critical", "Precautions should be taken against frost risk"], "recommended_tags": ["sonbahar", "kis-sebzesi"]}]}') ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
INSERT INTO `site_settings` (`id`,`key`,`locale`,`value`) VALUES (UUID(), 'planting_guide', 'de', '{"title": "Anbauleitfaden", "description": "Saisonale Anbauempfehlungen und Pflegetipps.", "seasons": [{"key": "spring", "label": "Frühling", "months": "März — Mai", "tips": ["Die Bodentemperatur sollte mindestens 15 °C betragen", "Die Anzucht der Setzlinge sollte Ende Februar beginnen", "Die erste Bewässerung sollte leicht und gleichmäßig erfolgen"], "recommended_tags": ["bahar", "fide"]}, {"key": "summer", "label": "Sommer", "months": "Juni — August", "tips": ["Gegen Hitzestress sollte beschattet werden", "Die Effizienz sollte durch Tröpfchenbewässerung gesteigert werden", "Auf die Erntezeiten sollte geachtet werden"], "recommended_tags": ["yaz", "sicaga-dayanikli"]}, {"key": "autumn", "label": "Herbst", "months": "September — November", "tips": ["Ideale Pflanzzeit für Wintergemüse", "Bodenvorbereitung und Düngung sind entscheidend", "Gegen Frostgefahr sollten Vorkehrungen getroffen werden"], "recommended_tags": ["sonbahar", "kis-sebzesi"]}]}') ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
INSERT INTO `site_settings` (`id`,`key`,`locale`,`value`) VALUES (UUID(), 'about_page', 'en', '{"hero": {"title": "About Us", "description": "Founded within the well-established Atakan Tohum to help shape the future of agriculture, Vista Seeds is a pioneering brand developing high-quality, high-yield seed varieties."}, "intro": {"title": "Vista Seeds", "content": "Vista Seeds is a seed brand established within Atakan Tohum İnşaat Mühendislik. Guided by the principles of innovation, quality and sustainability, we embrace a nature-respecting production model. Through modern breeding techniques and R&D, we offer disease-resistant hybrid seeds with strong adaptability.", "subtitle": "A multidisciplinary structure combining agriculture, energy and engineering investments."}, "stats": [{"label": "Expert Staff", "value": "100+", "description": "The founding year of our story"}, {"label": "Employees", "value": "250+", "description": "Production and operations"}, {"label": "Customers", "value": "137K+", "description": "Agriculture, R&D and field experts"}, {"label": "Seed Varieties", "value": "8+", "description": "Active field staff across Türkiye"}], "values": [{"icon": "sprout", "title": "High-Yield Seeds", "description": "Registered, resilient and high-yield varieties, presented through a product catalog that can be filtered to the grower''s needs."}, {"icon": "shield", "title": "Quality and Trust", "description": "An environmentally conscious production approach supported by Bereket Fide and renewable energy investments."}, {"icon": "users", "title": "Grower Focus", "description": "Solutions suited to Türkiye''s climate conditions, field-tested and built around the farmer''s needs."}, {"icon": "flask", "title": "Research and Development", "description": "References, knowledge base and dealer network, made accessible and transparent through digital tools."}], "vision": {"title": "Our Vision", "content": "To maximize growers'' productivity with our registered and resilient seed varieties of high genetic potential. To be a reliable solution partner at every stage of agricultural production."}, "mission": {"title": "Our Mission", "content": "To become a brand of global standards with innovative solutions that bring together technology and nature in agriculture. To achieve growth integrated with renewable energy and modern engineering projects."}, "timeline": [{"year": "1988", "title": "First Step into Agriculture", "description": "The first corporate step of the agricultural venture."}, {"year": "1990", "title": "Founding of Şahin Ziraat", "description": "The start of professional activity in the sector with an organizational structure."}, {"year": "2006", "title": "Founding of Bereket Fide", "description": "A seedling production facility was established to support the production chain."}, {"year": "2017", "title": "Entry into Construction", "description": "Real estate investments with the Vista Lagoon and Vista Prestige residential projects."}, {"year": "2018", "title": "Tolkan Architecture", "description": "An architecture and engineering firm was established within the group."}, {"year": "2025", "title": "Atakan Tohum and Vista Seeds", "description": "A new era in seed breeding and production with a modern brand identity. The Vista Seeds brand was registered."}], "activities": {"items": [{"title": "Seed Breeding and Production", "description": "Breeding, production and marketing of hybrid peppers, rootstocks and other vegetable seeds."}, {"title": "References and Project Gallery", "description": "Presents group companies and project galleries with rich media content."}, {"title": "Construction and Real Estate", "description": "Delivers technical content, planting guides and editorial materials to growers."}, {"title": "Seedling Production", "description": "Professional seedling production facilities and support for farmers under the Bereket Fide brand."}], "title": "Areas of Activity"}, "memberships": {"items": [{"name": "Antalya Chamber of Commerce and Industry", "logo_url": "/uploads/about/memberships/atso.png", "description": "ATSO member", "website_url": "https://www.atso.org.tr"}, {"name": "Republic of Türkiye Ministry of Agriculture and Forestry", "logo_url": "/uploads/about/memberships/tarim-bakanligi.png", "description": "Licensed seed producer and distributor", "website_url": "https://www.tarimorman.gov.tr"}, {"name": "Seed Distributors Sub-Union", "logo_url": "/uploads/about/memberships/turktob-dagiticilari.png", "description": "Member within TÜRKTOB", "website_url": "https://www.turktob.org.tr"}, {"name": "Seed Industrialists and Producers Sub-Union", "logo_url": "/uploads/about/memberships/tsuab.png", "description": "TSÜAB member", "website_url": "https://www.turktob.org.tr"}], "title": "Organizations We Belong To"}, "group_companies": [{"name": "Atakan Tohum İnşaat Mühendislik", "role": "Parent company", "description": "The corporate umbrella and management center of the group."}, {"name": "Vista Seeds", "role": "Seed brand", "description": "Hybrid seed breeding, production and marketing."}, {"name": "Bereket Fide", "role": "Seedling production", "description": "Professional seedling production facilities."}, {"name": "Tolkan Architecture", "role": "Architecture", "description": "Construction and architecture projects."}]}') ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
INSERT INTO `site_settings` (`id`,`key`,`locale`,`value`) VALUES (UUID(), 'about_page', 'de', '{"hero": {"title": "Über uns", "description": "Vista Seeds wurde innerhalb des etablierten Unternehmens Atakan Tohum gegründet, um die Zukunft der Landwirtschaft mitzugestalten, und ist eine führende Marke, die hochwertige und ertragreiche Saatgutsorten entwickelt."}, "intro": {"title": "Vista Seeds", "content": "Vista Seeds ist eine Saatgutmarke, die innerhalb der Atakan Tohum İnşaat Mühendislik gegründet wurde. Geleitet von den Grundsätzen Innovation, Qualität und Nachhaltigkeit verfolgen wir ein naturschonendes Produktionsmodell. Mit modernen Zuchttechniken und F&E bieten wir krankheitsresistente Hybridsaatgüter mit hoher Anpassungsfähigkeit.", "subtitle": "Eine vielseitige Struktur, die Investitionen in Landwirtschaft, Energie und Ingenieurwesen vereint."}, "stats": [{"label": "Fachpersonal", "value": "100+", "description": "Das Gründungsjahr unserer Geschichte"}, {"label": "Mitarbeiter", "value": "250+", "description": "Produktion und Betrieb"}, {"label": "Kunden", "value": "137K+", "description": "Landwirtschafts-, F&E- und Feldexperten"}, {"label": "Saatgutsorten", "value": "8+", "description": "Aktives Feldpersonal in der gesamten Türkei"}], "values": [{"icon": "sprout", "title": "Ertragreiches Saatgut", "description": "Eingetragene, widerstandsfähige und ertragreiche Sorten, präsentiert über einen Produktkatalog, der nach den Bedürfnissen des Erzeugers gefiltert werden kann."}, {"icon": "shield", "title": "Qualität und Vertrauen", "description": "Ein umweltbewusster Produktionsansatz, unterstützt durch Bereket Fide und Investitionen in erneuerbare Energien."}, {"icon": "users", "title": "Erzeugerorientierung", "description": "Lösungen, die an die Klimabedingungen der Türkei angepasst, feldgetestet und auf die Bedürfnisse der Landwirte zugeschnitten sind."}, {"icon": "flask", "title": "Forschung und Entwicklung", "description": "Referenzen, Wissensdatenbank und Händlernetz, über digitale Werkzeuge zugänglich und transparent bereitgestellt."}], "vision": {"title": "Unsere Vision", "content": "Die Produktivität der Erzeuger mit unseren eingetragenen und widerstandsfähigen Saatgutsorten von hohem genetischem Potenzial zu maximieren. In jeder Phase der landwirtschaftlichen Produktion ein zuverlässiger Lösungspartner zu sein."}, "mission": {"title": "Unsere Mission", "content": "Mit innovativen Lösungen, die Technologie und Natur in der Landwirtschaft zusammenbringen, zu einer Marke mit globalen Standards zu werden. Wachstum integriert mit erneuerbaren Energien und modernen Ingenieurprojekten zu erreichen."}, "timeline": [{"year": "1988", "title": "Erster Schritt in die Landwirtschaft", "description": "Der erste unternehmerische Schritt des landwirtschaftlichen Vorhabens."}, {"year": "1990", "title": "Gründung von Şahin Ziraat", "description": "Der Beginn der professionellen Tätigkeit in der Branche mit einer Organisationsstruktur."}, {"year": "2006", "title": "Gründung von Bereket Fide", "description": "Zur Unterstützung der Produktionskette wurde eine Setzlingsproduktionsanlage errichtet."}, {"year": "2017", "title": "Einstieg in die Baubranche", "description": "Immobilieninvestitionen mit den Wohnprojekten Vista Lagoon und Vista Prestige."}, {"year": "2018", "title": "Tolkan Architektur", "description": "Innerhalb der Gruppe wurde ein Architektur- und Ingenieurbüro gegründet."}, {"year": "2025", "title": "Atakan Tohum und Vista Seeds", "description": "Eine neue Ära in der Saatgutzucht und -produktion mit moderner Markenidentität. Die Marke Vista Seeds wurde eingetragen."}], "activities": {"items": [{"title": "Saatgutzucht und -produktion", "description": "Zucht, Produktion und Vermarktung von Hybridpaprika, Veredelungsunterlagen und anderen Gemüsesaatgütern."}, {"title": "Referenzen und Projektgalerie", "description": "Präsentiert Gruppenunternehmen und Projektgalerien mit reichhaltigen Medieninhalten."}, {"title": "Bau und Immobilien", "description": "Liefert technische Inhalte, Anbauleitfäden und redaktionelle Materialien an die Erzeuger."}, {"title": "Setzlingsproduktion", "description": "Professionelle Setzlingsproduktionsanlagen und Unterstützung für Landwirte unter der Marke Bereket Fide."}], "title": "Tätigkeitsbereiche"}, "memberships": {"items": [{"name": "Industrie- und Handelskammer Antalya", "logo_url": "/uploads/about/memberships/atso.png", "description": "ATSO-Mitglied", "website_url": "https://www.atso.org.tr"}, {"name": "Ministerium für Landwirtschaft und Forsten der Republik Türkei", "logo_url": "/uploads/about/memberships/tarim-bakanligi.png", "description": "Lizenzierter Saatguterzeuger und -händler", "website_url": "https://www.tarimorman.gov.tr"}, {"name": "Untergruppe der Saatguthändler", "logo_url": "/uploads/about/memberships/turktob-dagiticilari.png", "description": "Mitglied innerhalb von TÜRKTOB", "website_url": "https://www.turktob.org.tr"}, {"name": "Untergruppe der Saatgutindustriellen und -erzeuger", "logo_url": "/uploads/about/memberships/tsuab.png", "description": "TSÜAB-Mitglied", "website_url": "https://www.turktob.org.tr"}], "title": "Organisationen, denen wir angehören"}, "group_companies": [{"name": "Atakan Tohum İnşaat Mühendislik", "role": "Muttergesellschaft", "description": "Das Unternehmensdach und Verwaltungszentrum der Gruppe."}, {"name": "Vista Seeds", "role": "Saatgutmarke", "description": "Hybridsaatgutzucht, Produktion und Vermarktung."}, {"name": "Bereket Fide", "role": "Setzlingsproduktion", "description": "Professionelle Setzlingsproduktionsanlagen."}, {"name": "Tolkan Architektur", "role": "Architektur", "description": "Bau- und Architekturprojekte."}]}') ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
